// scripts/upload-to-buffer.mjs
//
// Schedules the weekly social pack (generated by generate-social-content.mjs)
// to Buffer for automatic posting.
//
//   node scripts/upload-to-buffer.mjs
//
// Required env:
//   BUFFER_ACCESS_TOKEN          OAuth2 access token from buffer.com
//
// Optional env (auto-detected from /profiles.json otherwise):
//   BUFFER_TWITTER_PROFILE_ID    profile id for X / Twitter
//   BUFFER_INSTAGRAM_PROFILE_ID  profile id for Instagram
//
// Common flags:
//   --dry-run                    don't actually post; print what would be sent
//   --platforms=twitter,instagram   default: twitter,instagram
//   --start-date=YYYY-MM-DD      first post date; default: tomorrow (local)
//   --hour=16                    hour-of-day in --tz; default 16 (4 PM)
//   --tz=America/New_York        IANA timezone; default America/New_York
//   --image-base-url=URL         where day-N.png is publicly hosted;
//                                 default https://plixfy.com/social/weekly/
//   --copy-images                also copy the PNGs into public/social/weekly/
//                                 so Vercel will serve them after `git push`
//   --skip-images                schedule without an image (text + link card)
//   --list-profiles              print /profiles.json and exit
//
// Buffer's free plan allows 3 connected channels and up to 10 scheduled
// posts per channel — 7 posts × 2 channels stays well under that.
// Image URLs MUST be publicly reachable; Buffer fetches them server-side.

import { readFileSync, writeFileSync, copyFileSync, mkdirSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(here, '..');
const weeklyDir = join(repoRoot, 'scripts', 'output', 'weekly');
const publicSocialDir = join(repoRoot, 'public', 'social', 'weekly');

// ── Args ────────────────────────────────────────────────────────────────
const args = Object.fromEntries(
  process.argv.slice(2).map((a) => {
    const m = a.match(/^--([^=]+)(?:=(.*))?$/);
    return m ? [m[1], m[2] ?? true] : [a, true];
  }),
);

const DRY_RUN = !!args['dry-run'];
const LIST_ONLY = !!args['list-profiles'];
const COPY_IMAGES = !!args['copy-images'];
const SKIP_IMAGES = !!args['skip-images'];
const HOUR = Number(args.hour) || 16;
const TZ = args.tz || 'America/New_York';
const IMAGE_BASE_URL = (args['image-base-url'] || 'https://plixfy.com/social/weekly/').replace(/\/?$/, '/');
const PLATFORMS = (args.platforms || 'twitter,instagram')
  .split(',')
  .map((s) => s.trim().toLowerCase())
  .filter(Boolean);

const TOKEN = process.env.BUFFER_ACCESS_TOKEN;
if (!TOKEN) {
  console.error('ERROR: BUFFER_ACCESS_TOKEN env var is required.');
  console.error('Get one at https://buffer.com/developers/apps — create an app, then');
  console.error('copy the "Access Token" shown after authorising your account.');
  process.exit(1);
}

const PROFILE_ID_BY_SERVICE = {
  twitter: process.env.BUFFER_TWITTER_PROFILE_ID || null,
  instagram: process.env.BUFFER_INSTAGRAM_PROFILE_ID || null,
};

// Default start date: tomorrow in the configured timezone.
function todayIsoIn(tz) {
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return dtf.format(new Date());
}
const START_DATE = args['start-date'] || addDaysIso(todayIsoIn(TZ), 1);

function addDaysIso(iso, days) {
  const [y, m, d] = iso.split('-').map(Number);
  const utc = Date.UTC(y, m - 1, d) + days * 86_400_000;
  return new Date(utc).toISOString().slice(0, 10);
}

// ── Buffer API helpers ─────────────────────────────────────────────────

const API = 'https://api.bufferapp.com/1';

async function bufferGet(path) {
  const url = `${API}${path}${path.includes('?') ? '&' : '?'}access_token=${encodeURIComponent(TOKEN)}`;
  const res = await fetch(url);
  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = json?.error || `HTTP ${res.status}`;
    throw new Error(`GET ${path} failed: ${msg}`);
  }
  return json;
}

async function bufferPostForm(path, fields) {
  // Buffer's v1 API expects application/x-www-form-urlencoded.
  // Arrays use repeated keys: profile_ids[] = X & profile_ids[] = Y.
  const body = new URLSearchParams();
  body.set('access_token', TOKEN);
  for (const [k, v] of Object.entries(fields)) {
    if (v === undefined || v === null) continue;
    if (Array.isArray(v)) {
      for (const item of v) body.append(k, String(item));
    } else if (typeof v === 'object') {
      // Nested: media[photo] => media[photo]
      for (const [sk, sv] of Object.entries(v)) {
        if (sv === undefined || sv === null) continue;
        body.append(`${k}[${sk}]`, String(sv));
      }
    } else {
      body.set(k, String(v));
    }
  }
  const res = await fetch(`${API}${path}`, {
    method: 'POST',
    headers: { 'content-type': 'application/x-www-form-urlencoded' },
    body,
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = json?.error || `HTTP ${res.status}`;
    throw new Error(`POST ${path} failed: ${msg}`);
  }
  return json;
}

// ── Timezone-aware scheduler ───────────────────────────────────────────

// Convert "wall-clock HH:MM in tz on dateIso" to a UTC Date (DST-safe).
function wallClockToUTC(dateIso, hour, minute, tz) {
  const [y, m, d] = dateIso.split('-').map(Number);
  const guessUTC = Date.UTC(y, m - 1, d, hour, minute, 0);
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    hourCycle: 'h23',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });
  const parts = Object.fromEntries(
    dtf.formatToParts(new Date(guessUTC)).map((p) => [p.type, p.value]),
  );
  const wallAsUTC = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour),
    Number(parts.minute),
    Number(parts.second),
  );
  const offset = wallAsUTC - guessUTC; // tz offset at this instant
  return new Date(guessUTC - offset);
}

// ── Profile resolution ─────────────────────────────────────────────────

const SERVICE_ALIAS = {
  x: 'twitter',
  twitter: 'twitter',
  instagram: 'instagram',
  ig: 'instagram',
};

function normaliseService(s) {
  return SERVICE_ALIAS[s.toLowerCase()] || s.toLowerCase();
}

async function resolveProfileIds() {
  const all = await bufferGet('/profiles.json');
  const byService = {};
  for (const p of all) {
    const svc = normaliseService(p.service);
    if (!byService[svc]) byService[svc] = [];
    byService[svc].push(p);
  }
  const resolved = {};
  for (const wanted of PLATFORMS) {
    const svc = normaliseService(wanted);
    const overrideId = PROFILE_ID_BY_SERVICE[svc];
    if (overrideId) {
      resolved[svc] = { id: overrideId, source: 'env', service: svc };
      continue;
    }
    const candidates = byService[svc] || [];
    if (candidates.length === 0) {
      console.warn(`  warn: no connected ${svc} profile found in Buffer; skipping that platform.`);
      continue;
    }
    if (candidates.length > 1) {
      const names = candidates.map((c) => `${c.formatted_username || c.service_username} (${c.id})`).join(', ');
      console.warn(`  warn: multiple ${svc} profiles connected (${names}). Using first; set BUFFER_${svc.toUpperCase()}_PROFILE_ID to override.`);
    }
    const p = candidates[0];
    resolved[svc] = { id: p.id, source: 'auto', service: svc, username: p.formatted_username || p.service_username };
  }
  return { all, resolved };
}

// ── Image staging ──────────────────────────────────────────────────────

function copyImagesToPublic(entries) {
  mkdirSync(publicSocialDir, { recursive: true });
  for (const e of entries) {
    const src = join(weeklyDir, e.image);
    const dst = join(publicSocialDir, e.image);
    if (!existsSync(src)) {
      console.warn(`  warn: ${src} missing — generate-social-content.mjs first.`);
      continue;
    }
    copyFileSync(src, dst);
    console.log(`  copied ${e.image} → public/social/weekly/`);
  }
  console.log('  → commit + push to deploy these to Vercel before Buffer fetches them.');
}

// ── Build per-platform update body ─────────────────────────────────────

function buildUpdateBody({ entry, profileId, service, scheduledAtUTC }) {
  const platformKey = service; // 'twitter' | 'instagram'
  const text = platformKey === 'twitter' ? entry.twitter : entry.instagram;
  const imageUrl = SKIP_IMAGES ? null : `${IMAGE_BASE_URL}${entry.image}`;
  const fields = {
    text,
    profile_ids: [profileId],
    scheduled_at: Math.floor(scheduledAtUTC.getTime() / 1000),
    shorten: 'false',
  };
  if (imageUrl) {
    fields.media = {
      photo: imageUrl,
      thumbnail: imageUrl,
      link: entry.game.url,
      description: entry.game.title,
    };
  }
  return fields;
}

// ── Main ───────────────────────────────────────────────────────────────

async function main() {
  console.log('Buffer scheduler');
  console.log(`  dry-run: ${DRY_RUN}    platforms: ${PLATFORMS.join(',')}    start-date: ${START_DATE}    ${HOUR}:00 ${TZ}`);
  console.log(`  image base: ${SKIP_IMAGES ? '(none)' : IMAGE_BASE_URL}`);

  // Verify token + list profiles
  let me;
  try {
    me = await bufferGet('/user.json');
    console.log(`  buffer user: ${me.email || me.id}`);
  } catch (err) {
    console.error(`  ERROR: ${err.message}`);
    console.error('  Check your BUFFER_ACCESS_TOKEN at https://buffer.com/developers/apps.');
    process.exit(1);
  }

  if (LIST_ONLY) {
    const profiles = await bufferGet('/profiles.json');
    console.log('Connected profiles:');
    for (const p of profiles) {
      console.log(`  - ${p.service.padEnd(12)} ${p.formatted_username || p.service_username || ''}  id=${p.id}`);
    }
    return;
  }

  // Read posts.json
  const postsPath = join(weeklyDir, 'posts.json');
  if (!existsSync(postsPath)) {
    console.error(`ERROR: ${postsPath} not found. Run generate-social-content.mjs first.`);
    process.exit(1);
  }
  const pack = JSON.parse(readFileSync(postsPath, 'utf8'));
  const entries = pack.entries || [];
  if (entries.length === 0) {
    console.error('ERROR: posts.json has no entries.');
    process.exit(1);
  }
  console.log(`  loaded ${entries.length} entries from posts.json`);

  // Optionally stage images for plixfy.com
  if (COPY_IMAGES && !SKIP_IMAGES) {
    copyImagesToPublic(entries);
  }

  // Verify image URLs are reachable (skip check on dry-run)
  if (!SKIP_IMAGES && !DRY_RUN) {
    const sampleUrl = `${IMAGE_BASE_URL}${entries[0].image}`;
    try {
      const r = await fetch(sampleUrl, { method: 'HEAD' });
      if (!r.ok) {
        console.warn(`  warn: HEAD ${sampleUrl} → ${r.status}. Buffer needs publicly reachable image URLs.`);
        console.warn(`         Re-run with --copy-images and deploy, or pass --image-base-url=… or --skip-images.`);
      } else {
        console.log(`  image base reachable (HEAD ${sampleUrl} → ${r.status})`);
      }
    } catch (err) {
      console.warn(`  warn: could not HEAD-check ${sampleUrl}: ${err.message}`);
    }
  }

  // Resolve profile ids
  const { resolved } = await resolveProfileIds();
  if (Object.keys(resolved).length === 0) {
    console.error('ERROR: no usable profiles. Connect at least one Twitter or Instagram channel in Buffer.');
    process.exit(1);
  }
  for (const [svc, p] of Object.entries(resolved)) {
    console.log(`  ${svc.padEnd(10)} → ${p.id}  (${p.source}${p.username ? ', ' + p.username : ''})`);
  }

  // Schedule each entry on each resolved platform
  const results = [];
  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    const dateIso = addDaysIso(START_DATE, i);
    const scheduledAtUTC = wallClockToUTC(dateIso, HOUR, 0, TZ);
    console.log(`\nDay ${i + 1}/${entries.length} — ${dateIso} ${String(HOUR).padStart(2, '0')}:00 ${TZ}  (${scheduledAtUTC.toISOString()})`);
    console.log(`  game: ${entry.game.title}`);

    for (const [svc, profile] of Object.entries(resolved)) {
      const body = buildUpdateBody({ entry, profileId: profile.id, service: svc, scheduledAtUTC });
      const summary = {
        day: entry.day,
        date: dateIso,
        scheduledAtUTC: scheduledAtUTC.toISOString(),
        service: svc,
        profileId: profile.id,
        text: body.text,
        imageUrl: body.media?.photo || null,
        link: body.media?.link || null,
      };
      if (DRY_RUN) {
        console.log(`  [dry-run] ${svc}: would schedule (${body.text.length} chars${body.media ? ', +image' : ''})`);
        results.push({ ...summary, status: 'dry-run' });
        continue;
      }
      try {
        const res = await bufferPostForm('/updates/create.json', body);
        const ids = (res.updates || []).map((u) => u.id);
        console.log(`  ${svc}: scheduled (${ids.length} update id${ids.length === 1 ? '' : 's'}: ${ids.join(', ')})`);
        results.push({ ...summary, status: 'scheduled', updateIds: ids });
      } catch (err) {
        console.error(`  ${svc}: FAILED — ${err.message}`);
        results.push({ ...summary, status: 'error', error: err.message });
      }
    }
  }

  // Write a schedule log alongside posts.json
  const logPath = join(weeklyDir, 'buffer-schedule.json');
  writeFileSync(
    logPath,
    JSON.stringify(
      {
        ranAt: new Date().toISOString(),
        dryRun: DRY_RUN,
        startDate: START_DATE,
        hour: HOUR,
        tz: TZ,
        platforms: Object.keys(resolved),
        imageBaseUrl: SKIP_IMAGES ? null : IMAGE_BASE_URL,
        results,
      },
      null,
      2,
    ),
  );

  const ok = results.filter((r) => r.status === 'scheduled').length;
  const failed = results.filter((r) => r.status === 'error').length;
  const dry = results.filter((r) => r.status === 'dry-run').length;
  console.log(`\nDone. scheduled=${ok}  failed=${failed}  dry-run=${dry}`);
  console.log(`Log: ${logPath}`);
  if (failed > 0) process.exit(2);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
